{"command": "# Check the auth.json - is it empty/minimal?
python3 -c "
import json
d = json.load(open('/root/.hermes/workspace/meetings/auth.json'))
if isinstance(d, dict):
    print('Keys:', list(d.keys()))
    if 'cookies' in d: print(f'Cookies: {len(d[\"cookies\"])}')
    if 'origins' in d: print(f'Origins: {len(d[\"origins\"])}')
    # show first cookie if exists
    if d.get('cookies'):
        c = d['cookies'][0]
        print(f'First cookie: {c.get(\"name\",\"?\")} domain={c.get(\"domain\",\"?\")} value_len={len(c.get(\"value\",\"\"))}')
elif isinstance(d, list):
    print(f'List of {len(d)} items')
    if d: print(f'First: {json.dumps(d[0], indent=2)[:300]}')
